<div class="mb-3">
    <label>Name</label>
    <input class="form-control" @bind="Shipping.Name" />
</div>

<div class="mb-3">
    <label>Address</label>
    <input class="form-control" @bind="Shipping.Address" />
</div>

<div class="mb-3">
    <label>City</label>
    <input class="form-control" @bind="Shipping.City" />
</div>

<div class="mb-3">
    <label>Zip Code</label>
    <input class="form-control" @bind="Shipping.ZipCode" />
</div>

@if (!string.IsNullOrWhiteSpace(ValidationMessage))
{
    <div class="text-danger mb-3">@ValidationMessage</div>
}

<button class="btn btn-primary" @onclick="OnNext">Next</button>

@code {
    [Parameter] public ShippingInfo Shipping { get; set; } = new();
    [Parameter] public EventCallback OnValidNext { get; set; }

    private string? ValidationMessage;

    private async Task OnNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            ValidationMessage = "Name and Address are required.";
            return;
        }

        ValidationMessage = null;
        await OnValidNext.InvokeAsync();
    }
}
"}

